    graph_copy = graph_data.copy()

    # Locate the EK_AGG_BLOCK node with name 'ju1.a3.m3'
    target_node = None
    for node_id, node_data in graph_copy.nodes(data=True):
        if node_data.get('name') == 'ju1.a3.m3' and 'EK_AGG_BLOCK' in node_data.get('type', []):
            target_node = node_id
            break

    # If the target AGG_BLOCK is not found, return an empty list
    if target_node is None:
        result = []
        graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)
        return {'type': 'list', 'data': result, 'updated_graph': graph_json}

