    child_capacities = []
    for child in children:
        total_capacity = 0
        stack = [child]
        visited = set()
        while stack:
            cur = stack.pop()
            if cur in visited:
                continue
            visited.add(cur)
            # Traverse outgoing RK_CONTAINS edges
            for _, nbr, ed in graph_copy.out_edges(cur, data=True):
                if 'RK_CONTAINS' in ed.get('type', []):
                    # If neighbor is a PORT, add its capacity
                    if 'EK_PORT' in graph_copy.nodes[nbr].get('type', []):
                        total_capacity += graph_copy.nodes[nbr].get('physical_capacity_bps', 0)
                    else:
                        stack.append(nbr)
        child_name = graph_copy.nodes[child].get('name', child)
        child_capacities.append((child_name, total_capacity))

    # Rank children by total capacity (descending)
    ranked_children = sorted(child_capacities, key=lambda x: x[1], reverse=True)

    # Prepare the updated graph in JSON format
    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)

    # Return the result as specified
    return {
        'type': 'list',
        'data': ranked_children,
