    def subtree_capacity(start_node):
        total = 0
        stack = [start_node]
        visited = set()
        while stack:
            n = stack.pop()
            if n in visited:
                continue
            visited.add(n)
            node_data = graph_copy.nodes[n]
            if 'EK_PORT' in node_data.get('type', []):
                total += node_data.get('physical_capacity_bps', 0)
            for _, tgt, edata in graph_copy.out_edges(n, data=True):
                if 'RK_CONTAINS' in edata.get('type', []):
                    stack.append(tgt)
        return total

    children = []
