        if 'RK_CONTAINS' in edata.get('type', []):
            children.append(tgt)

    result = []
    for child in children:
        cap = subtree_capacity(child)
        result.append([child, cap])

    result.sort(key=lambda x: x[1], reverse=True)

    return_object = {
        'type': 'list',
